/* ============================================================
   SCATTER CHARM — pops in scrapbook-style as it scrolls into view,
   then can be dragged anywhere on the page and dropped.
   ============================================================ */
function ScatterCharm({ src, alt, top, side, offset, size, rotate, delay = 0 }) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  const [pos, setPos] = useState({ x: 0, y: 0 }); // drag offset from original spot
  const [dragging, setDragging] = useState(false);
  const dragInfo = useRef({ startX: 0, startY: 0, origX: 0, origY: 0 });

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setTimeout(() => setVisible(true), delay);
            obs.disconnect();
          }
        });
      },
      { threshold: 0.15, rootMargin: "0px 0px -10% 0px" }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [delay]);

  const handlePointerDown = (e) => {
    e.preventDefault();
    const point = e.touches ? e.touches[0] : e;
    dragInfo.current = {
      startX: point.clientX,
      startY: point.clientY,
      origX: pos.x,
      origY: pos.y,
    };
    setDragging(true);
  };

  useEffect(() => {
    if (!dragging) return;

    const handleMove = (e) => {
      const point = e.touches ? e.touches[0] : e;
      const dx = point.clientX - dragInfo.current.startX;
      const dy = point.clientY - dragInfo.current.startY;
      setPos({ x: dragInfo.current.origX + dx, y: dragInfo.current.origY + dy });
    };
    const handleUp = () => setDragging(false);

    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
    window.addEventListener("touchmove", handleMove, { passive: false });
    window.addEventListener("touchend", handleUp);
    return () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
      window.removeEventListener("touchmove", handleMove);
      window.removeEventListener("touchend", handleUp);
    };
  }, [dragging]);

  return (
    <div
      ref={ref}
      style={{
        position: "absolute",
        top,
        [side]: offset,
        width: size,
        zIndex: dragging ? 30 : 5,
        opacity: visible ? 1 : 0,
        touchAction: "none",
        cursor: dragging ? "grabbing" : "grab",
        transform: visible
          ? `translate(${pos.x}px, ${pos.y}px) rotate(${rotate}deg) scale(${dragging ? 1.08 : 1})`
          : `rotate(${rotate - 18}deg) scale(0.4) translateY(24px)`,
        transition: dragging
          ? "transform 0.05s linear"
          : "opacity 0.6s cubic-bezier(.2,.9,.3,1.3), transform 0.65s cubic-bezier(.2,.9,.3,1.3)",
        filter: dragging
          ? "drop-shadow(0 16px 24px rgba(0,0,0,0.28))"
          : "drop-shadow(0 8px 14px rgba(0,0,0,0.18))",
      }}
      onMouseDown={handlePointerDown}
      onTouchStart={handlePointerDown}
    >
      <img src={src} alt={alt} draggable="false" style={{ width: "100%", display: "block", pointerEvents: "none", userSelect: "none" }} />
    </div>
  );
}

