/* ============================================================
   CURSOR GLOW — a soft Tiffany-blue afterglow that follows the
   cursor, used only on the Garros × Tiffany page to quietly nod
   at the partner brand.
   ============================================================ */
function CursorGlow({ color = C.tiffany }) {
  const dotRef = useRef(null);
  const pos = useRef({ x: -200, y: -200 });
  const current = useRef({ x: -200, y: -200 });
  const [active, setActive] = useState(false);

  useEffect(() => {
    const handleMove = (e) => {
      pos.current = { x: e.clientX, y: e.clientY };
      if (!active) setActive(true);
    };
    const handleLeave = () => setActive(false);

    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseleave", handleLeave);

    let raf;
    const animate = () => {
      current.current.x += (pos.current.x - current.current.x) * 0.18;
      current.current.y += (pos.current.y - current.current.y) * 0.18;
      if (dotRef.current) {
        dotRef.current.style.transform = `translate(${current.current.x}px, ${current.current.y}px) translate(-50%, -50%)`;
      }
      raf = requestAnimationFrame(animate);
    };
    raf = requestAnimationFrame(animate);

    return () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseleave", handleLeave);
      cancelAnimationFrame(raf);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div
      ref={dotRef}
      aria-hidden="true"
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        width: 360,
        height: 360,
        borderRadius: "50%",
        background: `radial-gradient(circle, #BCE6E2 0%, #D9F0EE 35%, transparent 70%)`,
        pointerEvents: "none",
        zIndex: 1,
        opacity: active ? 0.5 : 0,
        transition: "opacity 0.5s ease",
        filter: "blur(6px)",
        mixBlendMode: "normal",
      }}
    />
  );
}

