/* ============================================================
   ROOT APP
   ============================================================ */
export default function App() {
  useFonts();
  const [view, setView] = useState("door");

  const navigate = (id) => {
    setView(id);
    window.scrollTo(0, 0);
  };

  const navAccent = {
    intro: C.goldDeep,
    experience: C.goldDeep,
    cartier: C.cartierRed,
    tag: "#3958B8",
    garros: C.tiffany,
  }[view];

  return (
    <div style={{ fontFamily: "Jost, sans-serif", WebkitFontSmoothing: "antialiased" }}>
      <Nav onNavigate={navigate} current={view} accent={navAccent} dark={false} />
      {view === "door" && <DoorPage onEnter={() => navigate("intro")} doorImg={doorImg} />}
      {view === "intro" && <IntroPage onNavigate={navigate} tennisImg={tennisImg} f1Img={f1Img} dogImg={dogImg} />}
      {view === "experience" && <ExperiencePage onNavigate={navigate} />}
      {view === "cartier" && (
        <CartierPage
          onNavigate={navigate}
          tennisImg={tennisImg}
          tigresseWatchImg={tigresseWatchImg}
          tigresseRingImg={tigresseRingImg}
          tigresseBraceletImg={tigresseBraceletImg}
        />
      )}
      {view === "tag" && (
        <TagPage
          onNavigate={navigate}
          benchHeroImg={benchHeroImg}
          helmetCharmImg={helmetCharmImg}
          f1CarCharmImg={f1CarCharmImg}
          poubelCharmImg={poubelCharmImg}
          champagneCharmImg={champagneCharmImg}
          espressoCharmImg={espressoCharmImg}
          jetskiCharmImg={jetskiCharmImg}
          bulovaAdImg={bulovaAdImg}
          clockVanishing2Img={clockVanishing2Img}
        />
      )}
      {view === "garros" && <GarrosPage onNavigate={navigate} tennisClayImg={tennisClayImg} tiffanyWindowImg={tiffanyWindowImg} />}
    </div>
  );
}
